export const etag = (options?: ETagOptions): MiddlewareHandler => {
  const retainedHeaders = options?.retainedHeaders ?? RETAINED_304_HEADERS
  const weak = options?.weak ?? false
  const generator = initializeGenerator(options?.generateDigest)

  return async function etag(c, next) {
    const ifNoneMatch = c.req.header('If-None-Match') ?? null

    await next()

    const res = c.res as Response
    let etag = res.headers.get('ETag')

    if (!etag) {
      if (!generator) {
        return
      }
      const hash = await generateDigest(
        // This type casing avoids the type error for `deno publish`
        res.clone().body as ReadableStream<Uint8Array<ArrayBuffer>>,
        generator
      )
      if (hash === null) {
        return
      }
      etag = weak ? `W/"${hash}"` : `"${hash}"`
    }

    if (etagMatches(etag, ifNoneMatch)) {
      c.res = new Response(null, {
        status: 304,
        statusText: 'Not Modified',
        headers: {
          ETag: etag,
        },
      })
      c.res.headers.forEach((_, key) => {
        if (retainedHeaders.indexOf(key.toLowerCase()) === -1) {
          c.res.headers.delete(key)
        }
      })
    } else {
      c.res.headers.set('ETag', etag)
    }
  }
}

insert(method: string, path: string, handler: T): Node<T> {
  this.#order = ++this.#order

  // eslint-disable-next-line @typescript-eslint/no-this-alias
  let curNode: Node<T> = this
  const parts = splitRoutingPath(path)

  const possibleKeys: string[] = []

  for (let i = 0, len = parts.length; i < len; i++) {
    const p: string = parts[i]
    const nextP = parts[i + 1]
    const pattern = getPattern(p, nextP)
    const key = Array.isArray(pattern) ? pattern[0] : p

    if (key in curNode.#children) {
      curNode = curNode.#children[key]
      if (pattern) {
        possibleKeys.push(pattern[1])
      }
      continue
    }

    curNode.#children[key] = new Node()

    if (pattern) {
      curNode.#patterns.push(pattern)
      possibleKeys.push(pattern[1])
    }
    curNode = curNode.#children[key]
  }

  curNode.#methods.push({
    [method]: {
      handler,
      possibleKeys: possibleKeys.filter((v, i, a) => a.indexOf(v) === i),
      score: this.#order,
    },
  })

  return curNode
}

import type { ParamIndexMap, Result, Router } from '../../router'
import { METHOD_NAME_ALL } from '../../router'

export type HandlerData<T> = [T, ParamIndexMap][]
export type StaticMap<T> = Record<string, Result<T>>
export type Matcher<T> = [RegExp, HandlerData<T>[], StaticMap<T>]
export type MatcherMap<T> = Record<string, Matcher<T> | null>

export const emptyParam: string[] = []
export function match<R extends Router<T>, T>(this: R, method: string, path: string): Result<T> {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const matchers: MatcherMap<T> = (this as any).buildAllMatchers()

  const match = ((method, path) => {
    const matcher = (matchers[method] || matchers[METHOD_NAME_ALL]) as Matcher<T>

    const staticMatch = matcher[2][path]
    if (staticMatch) {
      return staticMatch
    }

    const match = path.match(matcher[0])
    if (!match) {
      return [[], emptyParam]
    }

    const index = match.indexOf('', 1)
    return [matcher[1][index], match]
  }) as Router<T>['match']

  this.match = match
  return match(method, path)
}

function isSchemeSatisfied(scheme: OpenAPIV3_1.SecuritySchemeObject, c: Context): boolean {
  switch (scheme.type) {
    case 'http': {
      const authHeader = c.req.header('Authorization')

      if ('scheme' in scheme && scheme.scheme?.toLowerCase() === 'basic') {
        return isValidBasicAuth(authHeader)
      }

      if ('scheme' in scheme && scheme.scheme?.toLowerCase() === 'bearer') {
        return isValidBearerAuth(authHeader)
      }

      return false
    }
    case 'apiKey': {
      if (!('name' in scheme) || !scheme.name || !('in' in scheme)) {
        return false
      }

      const value =
        scheme.in === 'header'
          ? c.req.header(scheme.name)
          : scheme.in === 'query'
            ? c.req.query(scheme.name)
            : scheme.in === 'cookie'
              ? getCookie(c, scheme.name)
              : undefined

      return Boolean(value)
    }
    // OAuth 2.0 and OpenID Connect both carry a bearer token in the `Authorization` header.
    case 'oauth2':
    case 'openIdConnect':
      return isValidBearerAuth(c.req.header('Authorization'))
    default:
      return false
  }
}

function validator<
  Schema extends StandardSchemaV1,
  Target extends keyof ValidationTargets,
  E extends Env,
  P extends string,
  In = StandardSchemaV1.InferInput<Schema>,
  Out = StandardSchemaV1.InferOutput<Schema>,
  I extends Input = {
    in: HasUndefined<In> extends true
      ? {
          [K in Target]?: In extends ValidationTargets[K]
            ? In
            : { [K2 in keyof In]?: ValidationTargets[K][K2] };
        }
      : {
          [K in Target]: In extends ValidationTargets[K]
            ? In
            : { [K2 in keyof In]: ValidationTargets[K][K2] };
        };
    out: { [K in Target]: Out };
  },
  V extends I = I,
>(
  target: Target,
  schema: Schema,
  hook?: Hook<StandardSchemaV1.InferOutput<Schema>, E, P, Target>,
  options?: ResolverReturnType["options"],
): MiddlewareHandler<E, P, V> {
  const middleware = sValidator(target, schema, hook);

  // @ts-expect-error not typed well
  return Object.assign(middleware, {
    [uniqueSymbol]: {
      target,
      ...resolver(schema, options),
      options,
    },
  });
}

add(method: string, path: string, handler: T) {
  if (!this.#matchers[method]) {
    const all = this.#matchers[METHOD_NAME_ALL] as Matcher<T>
    const staticMap = {} as StaticMap<T>
    for (const key in all[2]) {
      staticMap[key] = [all[2][key][0].slice(), emptyParam] as Result<T>
    }
    this.#matchers[method] = [
      all[0],
      all[1].map((list) => (Array.isArray(list) ? list.slice() : 0)) as HandlerData<T>[],
      staticMap,
    ]
  }

  if (path === '/*' || path === '*') {
    const handlerData: [T, ParamIndexMap] = [handler, {}]
    if (method === METHOD_NAME_ALL) {
      for (const m in this.#matchers) {
        this.#addWildcard(m, handlerData)
      }
    } else {
      this.#addWildcard(method, handlerData)
    }
    return
  }

  const data = this.#relocateMap[path]
  if (!data) {
    throw new Error(`Path ${path} is not registered`)
  }
  for (const [indexes, map] of data) {
    if (method === METHOD_NAME_ALL) {
      for (const m in this.#matchers) {
        this.#addPath(m, path, handler, indexes, map)
      }
    } else {
      this.#addPath(method, path, handler, indexes, map)
    }
  }
}

async function resolveAssetBearerOrCookie(c: Context): Promise<{
  userId: string;
  apiKeyId?: string;
}> {
  const { token, malformed } = parseBearerToken(c.req.header("Authorization"));
  if (malformed) {
    throw new HTTPException(401, { message: "Unauthorized" });
  }

  if (token) {
    const apiKeyResult = await verifyApiKey(token);
    if (apiKeyResult?.valid && apiKeyResult.key) {
      return {
        userId: apiKeyResult.key.userId,
        apiKeyId: apiKeyResult.key.id,
      };
    }
    const sessionResult = await getSessionFromBearerOnlyHeaders(c);
    if (sessionResult?.user?.id) {
      return { userId: sessionResult.user.id };
    }
    throw new HTTPException(401, { message: "Unauthorized" });
  }

  const sessionResult = await auth.api.getSession({
    headers: c.req.raw.headers,
  });
  if (!sessionResult?.user) {
    throw new HTTPException(401, { message: "Unauthorized" });
  }

  return { userId: sessionResult.user.id };
}

function requirePermission(
	resource: string,
	action: string,
): MiddlewareHandler<{ Variables: RBACContext }> {
	return async (c, next) => {
		const user = c.get("user");
		const session = c.get("session");

		if (!user || !session) {
			throw new HTTPException(401, { message: "Authentication required" });
		}

		try {
			// Get user role from database or user object
			const userRole = (user.role as AppRole) || "user";

			// Check if user has the required permission
			if (
				!hasPermission(
					userRole,
					resource as keyof typeof import("../permissions").permissions,
					action,
				)
			) {
				throw new HTTPException(403, {
					message: `Insufficient permissions: ${resource}.${action}`,
				});
			}

			await next();
		} catch (error) {
			logError(error as Error, {
				operation: "permission_check",
				resource,
				action,
				user: c.get("user"),
			});
			throw new HTTPException(500, { message: "Permission check failed" });
		}
	};
}

handler = async (c: Context<Env, typeof entityType, RequestValidationTargets>) => {
  const db = c.get('db');
  const origin = new URL(c.req.url).origin;
  const { id } = c.req.valid('param');
  const user = await getCurentUser(c);

  if (!user) {
    return unauthorizedResponse(c, 'No user found');
  }

  const found = await db.select().from(ProjectsTable).where(eq(ProjectsTable.id, id));
  if (found.length === 0) {
    return notFoundResponse(c);
  }

  // Authorizarion
  if (found[0].ownerId !== user.id) {
    return unauthorizedResponse(c);
  }

  // Get all task lists for the project
  const taskLists = await db.select().from(TaskListsTable).where(eq(TaskListsTable.projectId, id));
  if (taskLists.length > 0) {
    return badRequestResponse(c, 'Project has task lists, delete them first', null, {
      error_code: 'ERR_PROJECT_NOT_EMPTY',
    });
  }

  // delete from DB
  await db.delete(ProjectsTable).where(eq(ProjectsTable.id, id));

  // Emit event
  await emitter.emitAsync('project:deleted', c, { projectId: id });

  return c.json<z.infer<typeof ResponseSchema>, 200>({
    data: {
      id,
      type: entityType,
      attributes: { id },
      links: {
        self: `${origin}/${entityType}/${id}}`,
      },
    },
  });
}

