import { Hono } from 'hono'
import { Page } from './pages/page'
import { Top } from './pages/top'

const app = new Hono()

// Model
export type Post = {
  id: string
  title: string
  body: string
}

const posts: Post[] = [
  { id: '1', title: 'Good Morning', body: 'Let us eat breakfast' },
  { id: '2', title: 'Good Afternoon', body: 'Let us eat Lunch' },
  { id: '3', title: 'Good Evening', body: 'Let us eat Dinner' },
  { id: '4', title: 'Good Night', body: 'Let us drink Beer' },
  { id: '5', title: 'こんにちは', body: '昼からビールを飲みます' }
]

// Logic
const getPosts = () => posts

const getPost = (id: string) => {
  return posts.find((post) => post.id == id)
}

// Controller
app.get('/', (c) => {
  const posts = getPosts()
  return c.html(<Top posts={posts} />)
})

app.get('/post/:id{[0-9]+}', (c) => {
  const id = c.req.param('id')
  const post = getPost(id)
  if (!post) return c.notFound()
  return c.html(<Page post={post} />)
})

export default app

export const Script = (options: Options): any => {
  const src = options.src
  if (options.prod ?? import.meta.env.PROD) {
    let manifest: Manifest | undefined = options.manifest
    if (!manifest) {
      const MANIFEST = import.meta.glob<{ default: Manifest }>('/dist/.vite/manifest.json', {
        eager: true,
      })
      for (const [, manifestFile] of Object.entries(MANIFEST)) {
        if (manifestFile['default']) {
          manifest = manifestFile['default']
          break
        }
      }
    }
    if (manifest) {
      const scriptInManifest = manifest[src.replace(/^\//, '')]
      if (scriptInManifest) {
        return (
          <HasIslands>
            <script
              type='module'
              async={!!options.async}
              src={`${ensureTrailngSlash(import.meta.env.BASE_URL)}${scriptInManifest.file}`}
              nonce={options.nonce}
            ></script>
          </HasIslands>
        )
      }
    }
    return <></>
  } else {
    return <script type='module' async={!!options.async} src={src} nonce={options.nonce}></script>
  }
}

getSchema() {
  const bodyParameters = this.meta.fields.omit(
    (this.params.urlParams || []).reduce((a, v) => ({ ...a, [v]: true }), {}),
  );
  const pathParameters = this.meta.fields.pick(
    (this.params.urlParams || []).reduce((a, v) => ({ ...a, [v]: true }), {}),
  );

  return {
    request: {
      body: contentJson(bodyParameters),
      params: Object.keys(pathParameters.shape).length ? pathParameters : undefined,
      ...this.schema?.request,
    },
    responses: {
      "201": {
        description: "Returns the created Object",
        ...contentJson(
          z.object({
            success: z.boolean(),
            result: this.meta.model.serializerSchema,
          }),
        ),
        ...this.schema?.responses?.[201],
      },
      ...InputValidationException.schema(),
      ...this.schema?.responses,
    },
    ...metaSchemaProps(this._meta),
    ...this.schema,
  };
}

