async function listR2Objects(
	c: AppContext,
	bucket_name: string,
	query: ListObjectsQuery
) {
	const prefix = query.prefix;
	const delimiter = query.delimiter;
	const cursor = query.cursor;
	const limit = query.per_page;

	// Try local first
	const r2 = getR2Binding(c.env, bucket_name);
	if (r2) {
		return executeListObjects(r2, { prefix, delimiter, cursor, limit }, c);
	}

	const ownerMiniflare = await findR2BucketOwner(c, bucket_name);
	if (ownerMiniflare) {
		const params = new URLSearchParams();
		if (prefix) params.set("prefix", prefix);
		if (delimiter) params.set("delimiter", delimiter);
		if (cursor) params.set("cursor", cursor);
		if (limit !== undefined) params.set("per_page", String(limit));
		const queryString = params.toString();
		const path = `/r2/buckets/${encodeURIComponent(bucket_name)}/objects${
			queryString ? `?${queryString}` : ""
		}`;

		const response = await fetchFromPeer(ownerMiniflare, path);
		if (response) return response;
	}

	return errorResponse(
		404,
		R2_ERROR_BUCKET_NOT_FOUND,
		"list objects: 'bucket not found'"
	);
}

async function deleteR2Objects(
	c: AppContext,
	bucket_name: string,
	body: DeleteObjectsBody
): Promise<Response> {
	const keys = body;
	if (keys.length === 0) {
		return errorResponse(
			400,
			10001,
			"Request body must be a non-empty array of keys"
		);
	}

	// Try local first
	const r2 = getR2Binding(c.env, bucket_name);
	if (r2) {
		await r2.delete(keys);
		return c.json(wrapResponse(keys.map((key) => ({ key }))));
	}

	const ownerMiniflare = await findR2BucketOwner(c, bucket_name);
	if (ownerMiniflare) {
		const path = `/r2/buckets/${encodeURIComponent(bucket_name)}/objects`;
		const response = await fetchFromPeer(ownerMiniflare, path, {
			method: "DELETE",
			headers: { "Content-Type": "application/json" },
			body: JSON.stringify(keys),
		});
		if (response) return response;
	}

	return errorResponse(
		404,
		R2_ERROR_BUCKET_NOT_FOUND,
		"delete: 'bucket not found'"
	);
}

async createResult(
  event: E,
  res: Response,
  options: Pick<HandleOptions, 'isContentTypeBinary'>
): Promise<APIGatewayProxyResult> {
  // determine whether the response body should be base64 encoded
  const contentType = res.headers.get('content-type')
  const isContentTypeBinary = options.isContentTypeBinary ?? defaultIsContentTypeBinary // overwrite default function if provided
  let isBase64Encoded = contentType && isContentTypeBinary(contentType) ? true : false

  if (!isBase64Encoded) {
    const contentEncoding = res.headers.get('content-encoding')
    isBase64Encoded = isContentEncodingBinary(contentEncoding)
  }

  const body = isBase64Encoded ? encodeBase64(await res.arrayBuffer()) : await res.text()

  const result: APIGatewayProxyResult = {
    body: body,
    statusCode: res.status,
    isBase64Encoded,
    ...('multiValueHeaders' in event && event.multiValueHeaders
      ? {
          multiValueHeaders: {},
        }
      : {
          headers: {},
        }),
  }

  this.setCookies(event, res, result)
  if (result.multiValueHeaders) {
    res.headers.forEach((value, key) => {
      result.multiValueHeaders[key] = [value]
    })
  } else {
    res.headers.forEach((value, key) => {
      result.headers[key] = value
    })
  }

  return result
}

hasUnsafeStyleValue = (value: string): boolean => {
  if (!unsafeStyleValueCharRe.test(value)) {
    return false
  }

  let quote = 0
  const blockStack: number[] = []
  for (let i = 0, len = value.length; i < len; i++) {
    const c = value.charCodeAt(i)
    if (c === 0x5c) {
      if (i === len - 1) {
        return true
      }
      i++
    } else if (quote !== 0) {
      if (c === 0x0a || c === 0x0c || c === 0x0d) {
        return true
      }
      if (c === quote) {
        quote = 0
      }
    } else if (c === 0x2f && value.charCodeAt(i + 1) === 0x2a) {
      const end = value.indexOf('*/', i + 2)
      if (end === -1) {
        return true
      }
      i = end + 1
    } else if (c === 0x22 || c === 0x27) {
      quote = c
    } else if (c === 0x28) {
      blockStack.push(0x29)
    } else if (c === 0x5b) {
      blockStack.push(0x5d)
    } else if (c === 0x7b || c === 0x7d) {
      return true
    } else if (c === 0x29 || c === 0x5d) {
      if (blockStack[blockStack.length - 1] !== c) {
        return true
      }
      blockStack.pop()
    } else if (c === 0x3b && blockStack.length === 0) {
      return true
    }
  }
  return quote !== 0 || blockStack.length !== 0
}

async function updateMeOp(ctx: AuthContext, input: UpdateMeInput) {
  const user = ctx.var.user;

  if (!user) throw new AppError(404, 'not_found', 'warn', { entityType: 'user', meta: { user: 'self' } });

  const { userFlags, slug, firstName, lastName, ...rest } = input;

  if (slug && slug !== user.slug) {
    const slugAvailable = await checkSlugAvailable(ctx, slug, 'user');
    if (!slugAvailable) throw new AppError(409, 'slug_exists', 'warn', { entityType: 'user', meta: { slug } });
  }

  const updateData = {
    ...rest,
    ...(slug && { slug }),
    ...(firstName !== undefined && { firstName }),
    ...(lastName !== undefined && { lastName }),
    ...(userFlags && { userFlags }),
    ...((firstName || lastName) && { name: [firstName, lastName].filter(Boolean).join(' ') }),
    updatedAt: getIsoDate(),
    updatedBy: user.id,
  };

  await updateMe(ctx, { values: updateData as UpdateMeOpts['values'] });
  invalidateCache.user(user.id);

  const userWithActivity = await findUserById(ctx);
  return userWithActivity;
}

async create(data: O<typeof this._meta>): Promise<O<typeof this._meta>> {
  const tableName = validateTableName(this.meta.model.tableName);
  const validColumns = this.getValidColumns();

  // Validate all column names from the data
  const columns = Object.keys(data).map((col) => validateColumnName(col, validColumns));
  const values = Object.values(data);

  // Build parameterized query
  const columnList = columns.join(", ");
  const placeholders = values.map((_, i) => `?${i + 1}`).join(", ");
  const sql = `INSERT INTO ${tableName} (${columnList}) VALUES (${placeholders}) RETURNING *`;

  try {
    const result = await this.getDBBinding()
      .prepare(sql)
      .bind(...values)
      .all();

    const inserted = result.results[0] as O<typeof this._meta>;

    if (this.logger) {
      this.logger.log(`Successfully created record in ${tableName}`);
    }

    return inserted;
  } catch (e: unknown) {
    handleDbError(e as Error, this.constraintsMessages, this.logger, `create ${tableName}`);
  }
}

createRequest = (event: CloudFrontEdgeEvent): Request => {
  const queryString = event.Records[0].cf.request.querystring
  const host =
    event.Records[0].cf.request.headers?.host?.[0]?.value ||
    event.Records[0].cf.config.distributionDomainName
  const urlPath = `https://${host}${event.Records[0].cf.request.uri}`
  const url = queryString ? `${urlPath}?${queryString}` : urlPath

  const headers = new Headers()
  Object.entries(event.Records[0].cf.request.headers).forEach(([k, v]) => {
    v.forEach((header) => headers.append(k, header.value))
  })

  const requestBody = event.Records[0].cf.request.body
  const method = event.Records[0].cf.request.method
  const rawBody = createBody(method, requestBody)

  let body: string | Uint8Array<ArrayBuffer> | undefined = rawBody
  if (rawBody !== undefined) {
    const bytes =
      typeof rawBody === 'string'
        ? (new TextEncoder().encode(rawBody) as Uint8Array<ArrayBuffer>)
        : rawBody
    body = bytes
    headers.set('content-length', bytes.length.toString())
  }

  return new Request(url, {
    headers,
    method,
    body,
  })
}

createSuccessResponseSchema = <
