getContentFromKVAsset = async (
  path: string,
  options?: KVAssetOptions
): Promise<ReadableStream | null> => {
  let ASSET_MANIFEST: Record<string, string>

  if (options && options.manifest) {
    if (typeof options.manifest === 'string') {
      ASSET_MANIFEST = JSON.parse(options.manifest)
    } else {
      ASSET_MANIFEST = options.manifest as Record<string, string>
    }
  } else {
    if (typeof __STATIC_CONTENT_MANIFEST === 'string') {
      ASSET_MANIFEST = JSON.parse(__STATIC_CONTENT_MANIFEST)
    } else {
      ASSET_MANIFEST = __STATIC_CONTENT_MANIFEST
    }
  }

  // ASSET_NAMESPACE is KVNamespace
  let ASSET_NAMESPACE: unknown
  if (options && options.namespace) {
    ASSET_NAMESPACE = options.namespace
  } else {
    ASSET_NAMESPACE = __STATIC_CONTENT
  }

  const key = ASSET_MANIFEST[path]
  if (!key) {
    return null
  }

  // @ts-expect-error ASSET_NAMESPACE is not typed
  const content = await ASSET_NAMESPACE.get(key, { type: 'stream' })
  if (!content) {
    return null
  }
  return content as unknown as ReadableStream
}

cssCommon = (
  strings: TemplateStringsArray,
  values: CssVariableType[],
  classNameSlug?: ClassNameSlug,
  onInvalidSlug?: OnInvalidSlug
): CssClassName => {
  let [label, thisStyleString, selectors, externalClassNames] = buildStyleString(strings, values)
  const isPseudoGlobal = isPseudoGlobalSelectorRe.exec(thisStyleString)
  if (isPseudoGlobal) {
    thisStyleString = isPseudoGlobal[1]
  }
  const hash = toHash(label + thisStyleString)

  let customSlug: string | undefined
  if (classNameSlug) {
    const slug = classNameSlug(hash, normalizeLabel(label), thisStyleString)
    if (slug) {
      if (isValidClassName(slug)) {
        customSlug = slug
      } else {
        ;(onInvalidSlug || defaultOnInvalidSlug)(slug)
      }
    }
  }

  const selector = (isPseudoGlobal ? PSEUDO_GLOBAL_SELECTOR : '') + (customSlug || hash)
  const className = (
    isPseudoGlobal ? selectors.map((s) => s[CLASS_NAME]) : [selector, ...externalClassNames]
  ).join(' ')

  return {
    [SELECTOR]: selector,
    [CLASS_NAME]: className,
    [STYLE_STRING]: thisStyleString,
    [SELECTORS]: selectors,
    [EXTERNAL_CLASS_NAMES]: externalClassNames,
  }
}

sendMatrixMessage = async ({
  msgtype,
  textMessage,
  html,
}: {
  msgtype: MatrixMsgTypes;
  textMessage: string;
  html?: string;
}) => {
  if (!env.ELEMENT_ROOM_ID || !env.ELEMENT_BOT_ACCESS_TOKEN) {
    logEvent(null, 'info', 'Missing required Element env values (roomId and/or  botAccessToken).');
    return;
  }
  // Construct payload
  const bodyPayload: Record<string, unknown> = {
    msgtype,
    body: textMessage,
    ...(html ? { format: 'org.matrix.custom.html', formatted_body: html } : {}),
  };

  // Build Matrix send message URL
  const txnId = nanoid(6);
  const roomId = env.ELEMENT_ROOM_ID;
  const botAccessToken = env.ELEMENT_BOT_ACCESS_TOKEN;
  const eventType = 'm.room.message';

  const url = `${appConfig.matrixURL}/_matrix/client/v3/rooms/${roomId}/send/${eventType}/${txnId}?access_token=${botAccessToken}`;

  const matrixResponse = await fetch(url, {
    method: 'PUT',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(bodyPayload),
  });

  if (matrixResponse.ok) {
    logEvent(null, 'info', 'Matrix message sent successfully to specified room');
  } else {
    const errorBody = await matrixResponse.json();
    logError(null, 'Failed to send Matrix message', errorBody);
  }
  return matrixResponse;
}

getParams = (templateId: UploadTemplateId, isPublic: boolean, sub: string) => {
  // Transloadit security requires us to set an expiration date like this
  const expires = utcDateString(Date.now() + 1 * 60 * 60 * 1000); // 1 hour

  // And a nonce to prevent replay attacks
  const nonce = nanoid(16);

  const authKey = env.TRANSLOADIT_KEY;
  const authSecret = env.TRANSLOADIT_SECRET;
  if (!authKey || !authSecret) throw Error('auth_key_not_found');

  const template = uploadTemplates[templateId];

  return {
    auth: {
      key: authKey,
      expires,
      nonce,
    },
    steps: {
      ':original': { robot: '/upload/handle' },
      // Inject steps based on template: avatar thumbnail, cover image, attachments ...
      ...template.steps,
      exported: {
        // Use is also based on template data
        use: template.use,
        robot: '/s3/store',
        credentials: isPublic ? appConfig.s3.publicBucket : appConfig.s3.privateBucket,
        host: appConfig.s3.host,
        no_vhost: true,
        url_prefix: '',
        acl: isPublic ? 'public-read' : 'private',
        path: `/${sub}/\${file.id}.\${file.url_name}`,
      },
    },
  };
}
